import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is the difference between simple and compound interest?", a: "Simple interest is calculated only on principal. Compound interest earns interest on principal plus previously earned interest." },
  { q: "How do you calculate compound interest?", a: "Use A = P(1 + r/n)^(nt), where P is principal, r is annual rate, n is compounding periods per year, and t is years." },
  { q: "What does compounding frequency mean?", a: "Compounding frequency is how often interest is added to the balance, such as monthly or daily." },
  { q: "How does the Rule of 72 work?", a: "Divide 72 by the annual return percentage to estimate how many years it takes money to double." },
  { q: "What is APY vs APR?", a: "APR is the stated annual rate. APY includes compounding and shows the effective annual yield." },
];
const money = (n: number) => formatCurrencyValue(n, { maximumFractionDigits: 2 });
const amount = (p: number, r: number, t: number, n: number, compound: boolean) => compound ? p * Math.pow(1 + r / 100 / n, n * t) : p * (1 + r / 100 * t);

export default function InterestCalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState<"simple" | "compound">("compound");
  const [principal, setPrincipal] = useState(10000);
  const [rate, setRate] = useState(5);
  const [years, setYears] = useState(10);
  const [frequency, setFrequency] = useState(12);
  const finalAmount = amount(principal, rate, years, frequency, mode === "compound");
  const interest = finalAmount - principal;
  const growth = useMemo(() => Array.from({ length: years }, (_, i) => { const y = i + 1; const total = amount(principal, rate, y, frequency, mode === "compound"); return { y, interest: total - principal, total }; }), [principal, rate, years, frequency, mode]);
  const comparison = [1, 5, 10, 20, 30].map((y) => { const simple = amount(10000, 5, y, 1, false); const monthly = amount(10000, 5, y, 12, true); const daily = amount(10000, 5, y, 365, true); return { y, simple, monthly, daily, diff: daily - simple }; });
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  return (
    <>
      <SEOHead title="Free Interest Calculator Online - Calculate Simple and Compound Interest Instantly | CalcHive" description="Free online interest calculator. Calculate simple and compound interest for any principal, rate and time period with year by year breakdown instantly. 100% free, no signup required." canonical="/interest-calculator" keywords="free interest calculator, compound interest calculator free online, simple interest calculator free, calculate interest earned free, savings interest calculator free online" category="Financial Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Interest Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate simple and compound interest with a year-by-year growth table.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">{[["Principal", principal, setPrincipal], ["Rate (%)", rate, setRate], ["Years", years, setYears], ["Compounds per year", frequency, setFrequency]].map(([l,v,s]) => <div key={l as string}><label className="text-sm font-semibold text-foreground block mb-2">{l as string}</label><input type="number" value={v as number} onChange={(e) => (s as (n:number)=>void)(Number(e.target.value))} className={inputClass} /></div>)}<div><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value as "simple" | "compound")} className={inputClass}><option value="simple">Simple Interest</option><option value="compound">Compound Interest</option></select></div></div><motion.div key={`${mode}-${principal}-${rate}-${years}-${frequency}`} initial={{opacity:.7,y:4}} animate={{opacity:1,y:0}}><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Final Amount</p><p className="text-6xl font-black text-white" data-testid="result-interest">{money(finalAmount)}</p><p className="text-white/70 text-sm mt-1">Interest earned: {money(interest)}</p></div></motion.div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Simple and Compound Interest for Free</h2><p className="text-muted-foreground leading-relaxed">Simple interest uses I = PRT. Compound interest uses A = P(1 + r/n)^nt.</p><h2 className="text-2xl font-bold text-foreground">How Compounding Frequency Affects Your Interest Earnings</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Interest Earned on $10,000 Over Time</caption><thead className="bg-muted/60"><tr>{["Years","Simple Interest (5%)","Compound Monthly (5%)","Compound Daily (5%)","Difference"].map(h=><th key={h} className="text-left py-3 px-3 font-semibold">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map(r=><tr key={r.y}><td className="py-2.5 px-3 font-semibold">{r.y}</td><td className="py-2.5 px-3">{money(r.simple)}</td><td className="py-2.5 px-3">{money(r.monthly)}</td><td className="py-2.5 px-3">{money(r.daily)}</td><td className="py-2.5 px-3">{money(r.diff)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Interest Earnings Calculator for Everyone</h2><div className="overflow-x-auto max-h-96"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Year by Year Growth</caption><thead className="bg-muted/60 sticky top-0"><tr><th className="text-left py-3 px-3">Year</th><th className="text-left py-3 px-3">Interest Earned</th><th className="text-left py-3 px-3">Final Amount</th></tr></thead><tbody className="divide-y divide-border">{growth.map(r=><tr key={r.y}><td className="py-2 px-3">{r.y}</td><td className="py-2 px-3">{money(r.interest)}</td><td className="py-2 px-3">{money(r.total)}</td></tr>)}</tbody></table></div></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/interest-calculator" headingLevel="h3" /></main>
    </>
  );
}


